using System;
using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Models
{
    public class PaginatedListTests
    {
        [Fact]
        public void Constructor_SetsPropertiesCorrectly()
        {
            var items = new List<string> { "a", "b", "c" };
            var list = new PaginatedList<string>(items, 10, 2, 3);

            Assert.Equal(2, list.PageIndex);
            Assert.Equal(4, list.TotalPages); // ceil(10/3) = 4
            Assert.Equal(3, list.Count);
            Assert.Contains("a", list);
            Assert.Contains("b", list);
            Assert.Contains("c", list);
        }

        [Fact]
        public void TotalPages_CalculatedCorrectly_ExactDivision()
        {
            var list = new PaginatedList<int>(new List<int>(), 10, 1, 5);
            Assert.Equal(2, list.TotalPages); // 10/5 = 2
        }

        [Fact]
        public void TotalPages_CalculatedCorrectly_WithRemainder()
        {
            var list = new PaginatedList<int>(new List<int>(), 11, 1, 5);
            Assert.Equal(3, list.TotalPages); // ceil(11/5) = 3
        }

        [Fact]
        public void TotalPages_IsOneForSinglePage()
        {
            var list = new PaginatedList<int>(new List<int>(), 3, 1, 10);
            Assert.Equal(1, list.TotalPages);
        }

        [Fact]
        public void TotalPages_IsZeroForNoItems()
        {
            var list = new PaginatedList<int>(new List<int>(), 0, 1, 10);
            Assert.Equal(0, list.TotalPages);
        }

        [Fact]
        public void HasPreviousPage_FalseOnFirstPage()
        {
            var list = new PaginatedList<int>(new List<int>(), 10, 1, 5);
            Assert.False(list.HasPreviousPage);
        }

        [Fact]
        public void HasPreviousPage_TrueOnSecondPage()
        {
            var list = new PaginatedList<int>(new List<int>(), 10, 2, 5);
            Assert.True(list.HasPreviousPage);
        }

        [Fact]
        public void HasNextPage_TrueWhenNotLastPage()
        {
            var list = new PaginatedList<int>(new List<int>(), 10, 1, 5);
            Assert.True(list.HasNextPage);
        }

        [Fact]
        public void HasNextPage_FalseOnLastPage()
        {
            var list = new PaginatedList<int>(new List<int>(), 10, 2, 5);
            Assert.False(list.HasNextPage);
        }

        [Fact]
        public void HasNextPage_FalseWhenNoItems()
        {
            var list = new PaginatedList<int>(new List<int>(), 0, 1, 10);
            Assert.False(list.HasNextPage);
        }

        [Fact]
        public void Create_ReturnsCorrectPageOfItems()
        {
            var source = Enumerable.Range(1, 25).AsQueryable();

            var page1 = PaginatedList<int>.Create(source, 1, 10);
            Assert.Equal(10, page1.Count);
            Assert.Equal(1, page1.First());
            Assert.Equal(10, page1.Last());
            Assert.Equal(1, page1.PageIndex);
            Assert.Equal(3, page1.TotalPages);

            var page2 = PaginatedList<int>.Create(source, 2, 10);
            Assert.Equal(10, page2.Count);
            Assert.Equal(11, page2.First());
            Assert.Equal(20, page2.Last());

            var page3 = PaginatedList<int>.Create(source, 3, 10);
            Assert.Equal(5, page3.Count);
            Assert.Equal(21, page3.First());
            Assert.Equal(25, page3.Last());
        }

        [Fact]
        public void Create_EmptySource_ReturnsEmptyList()
        {
            var source = Enumerable.Empty<int>().AsQueryable();
            var list = PaginatedList<int>.Create(source, 1, 10);

            Assert.Empty(list);
            Assert.Equal(0, list.TotalPages);
            Assert.Equal(1, list.PageIndex);
        }

        [Fact]
        public void Create_SingleItemPerPage()
        {
            var source = new[] { "a", "b", "c" }.AsQueryable();
            var page2 = PaginatedList<string>.Create(source, 2, 1);

            Assert.Single(page2);
            Assert.Equal("b", page2[0]);
            Assert.Equal(3, page2.TotalPages);
            Assert.True(page2.HasPreviousPage);
            Assert.True(page2.HasNextPage);
        }
    }
}

using ContosoUniversity.Models;
using ContosoUniversity.Services;
using System;
using System.Collections.Generic;
using System.Linq;
using System.Threading.Tasks;
using Xunit;

namespace ContosoUniversity.Tests.Services
{
    public class NotificationServiceTests : IDisposable
    {
        private readonly NotificationService _service;

        public NotificationServiceTests()
        {
            _service = new NotificationService();
            // Drain the shared static queue before each test
            while (_service.ReceiveNotification() != null) { }
        }

        public void Dispose()
        {
            _service.Dispose();
        }

        [Fact]
        public void SendNotification_EnqueuesNotification()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE, "TestUser");

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("1", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
            Assert.Equal("TestUser", notification.CreatedBy);
            Assert.False(notification.IsRead);
        }

        [Fact]
        public void SendNotification_WithDisplayName_GeneratesCorrectMessage()
        {
            _service.SendNotification("Student", "1", "Carson Alexander", EntityOperation.CREATE, "Admin");

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Contains("Carson Alexander", notification.Message);
            Assert.Contains("Student", notification.Message);
            Assert.Contains("created", notification.Message);
        }

        [Fact]
        public void SendNotification_WithoutDisplayName_UsesIdInMessage()
        {
            _service.SendNotification("Student", "42", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Contains("ID: 42", notification.Message);
        }

        [Fact]
        public void SendNotification_DefaultUserIsSystem()
        {
            _service.SendNotification("Course", "100", EntityOperation.UPDATE);

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("System", notification.CreatedBy);
        }

        [Theory]
        [InlineData(EntityOperation.CREATE, "created")]
        [InlineData(EntityOperation.UPDATE, "updated")]
        [InlineData(EntityOperation.DELETE, "deleted")]
        public void SendNotification_GeneratesCorrectMessageForOperation(EntityOperation operation, string expectedVerb)
        {
            _service.SendNotification("Department", "1", "English", operation);

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Contains(expectedVerb, notification.Message);
        }

        [Fact]
        public void SendNotification_SetsOperationString()
        {
            _service.SendNotification("Course", "1", EntityOperation.UPDATE);
            var notification = _service.ReceiveNotification();
            Assert.Equal("UPDATE", notification.Operation);
        }

        [Fact]
        public void SendNotification_SetsCreatedAt()
        {
            var before = DateTime.Now.AddSeconds(-1);
            _service.SendNotification("Student", "1", EntityOperation.CREATE);
            var after = DateTime.Now.AddSeconds(1);

            var notification = _service.ReceiveNotification();
            Assert.InRange(notification.CreatedAt, before, after);
        }

        [Fact]
        public void ReceiveNotification_ReturnsNullWhenQueueEmpty()
        {
            var notification = _service.ReceiveNotification();
            Assert.Null(notification);
        }

        [Fact]
        public void ReceiveNotification_ReturnsFIFOOrder()
        {
            _service.SendNotification("Type1", "1", EntityOperation.CREATE);
            _service.SendNotification("Type2", "2", EntityOperation.UPDATE);
            _service.SendNotification("Type3", "3", EntityOperation.DELETE);

            var n1 = _service.ReceiveNotification();
            var n2 = _service.ReceiveNotification();
            var n3 = _service.ReceiveNotification();

            Assert.Equal("Type1", n1.EntityType);
            Assert.Equal("Type2", n2.EntityType);
            Assert.Equal("Type3", n3.EntityType);
        }

        [Fact]
        public void ReceiveNotification_RemovesFromQueue()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);

            var first = _service.ReceiveNotification();
            var second = _service.ReceiveNotification();

            Assert.NotNull(first);
            Assert.Null(second);
        }

        [Fact]
        public void MarkAsRead_DoesNotThrow()
        {
            // MarkAsRead is a no-op in the in-memory implementation
            var exception = Record.Exception(() => _service.MarkAsRead(1));
            Assert.Null(exception);
        }

        [Fact]
        public void SendNotification_OverloadWithoutDisplayName()
        {
            _service.SendNotification("Course", "5", EntityOperation.DELETE);

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("Course", notification.EntityType);
            Assert.Equal("5", notification.EntityId);
            Assert.Equal("DELETE", notification.Operation);
        }

        [Fact]
        public void Dispose_DoesNotThrow()
        {
            var service = new NotificationService();
            var exception = Record.Exception(() => service.Dispose());
            Assert.Null(exception);
        }

        [Fact]
        public void SendNotification_MultipleNotificationsCanBeQueued()
        {
            for (int i = 0; i < 20; i++)
            {
                _service.SendNotification("Entity", i.ToString(), EntityOperation.CREATE);
            }

            var received = new List<Notification>();
            Notification n;
            while ((n = _service.ReceiveNotification()) != null)
            {
                received.Add(n);
            }

            Assert.Equal(20, received.Count);
        }

        [Fact]
        public void SendNotification_WithEmptyDisplayName_UsesIdInMessage()
        {
            _service.SendNotification("Student", "42", "", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Contains("ID: 42", notification.Message);
        }

        [Fact]
        public void SendNotification_WithWhitespaceDisplayName_UsesIdInMessage()
        {
            _service.SendNotification("Student", "42", "   ", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Contains("ID: 42", notification.Message);
        }

        [Fact]
        public void SendNotification_CreateOperation_MessageFormat()
        {
            _service.SendNotification("Course", "100", "Chemistry", EntityOperation.CREATE);
            var n = _service.ReceiveNotification();
            Assert.Equal("New Course 'Chemistry' has been created", n.Message);
        }

        [Fact]
        public void SendNotification_UpdateOperation_MessageFormat()
        {
            _service.SendNotification("Course", "100", "Chemistry", EntityOperation.UPDATE);
            var n = _service.ReceiveNotification();
            Assert.Equal("Course 'Chemistry' has been updated", n.Message);
        }

        [Fact]
        public void SendNotification_DeleteOperation_MessageFormat()
        {
            _service.SendNotification("Course", "100", "Chemistry", EntityOperation.DELETE);
            var n = _service.ReceiveNotification();
            Assert.Equal("Course 'Chemistry' has been deleted", n.Message);
        }

        [Fact]
        public void SendNotification_WithoutDisplayName_CreateMessageFormat()
        {
            _service.SendNotification("Student", "42", EntityOperation.CREATE);
            var n = _service.ReceiveNotification();
            Assert.Equal("New Student (ID: 42) has been created", n.Message);
        }
    }
}

using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using System;
using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class HomeControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly HomeController _controller;

        public HomeControllerTests()
        {
            _context = TestDbContextHelper.CreateSeededContext();
            _controller = new HomeController(_context);
            SetupController(_controller);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        private static void SetupController(Controller controller)
        {
            controller.ControllerContext = new ControllerContext
            {
                HttpContext = new DefaultHttpContext()
            };
            controller.TempData = new TempDataDictionary(
                controller.ControllerContext.HttpContext,
                new SessionStateTempDataProvider(new NullTempDataSerializer()));
        }

        [Fact]
        public void Index_ReturnsViewResult()
        {
            var result = _controller.Index();
            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void About_ReturnsViewResultWithEnrollmentDateGroups()
        {
            var result = _controller.About();

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<List<EnrollmentDateGroup>>(viewResult.Model);
            Assert.NotEmpty(model);
        }

        [Fact]
        public void About_GroupsStudentsByEnrollmentDate()
        {
            var result = _controller.About();
            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<List<EnrollmentDateGroup>>(viewResult.Model);

            // We have 3 students with dates: 2010-09-01, 2012-09-01, 2013-09-01
            Assert.Equal(3, model.Count);
            Assert.All(model, g => Assert.True(g.StudentCount > 0));
        }

        [Fact]
        public void Contact_ReturnsViewResult()
        {
            var result = _controller.Contact();

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.Equal("Your contact page.", _controller.ViewBag.Message);
        }

        [Fact]
        public void Error_ReturnsViewResult()
        {
            var result = _controller.Error();
            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Unauthorized_ReturnsViewResult()
        {
            var result = _controller.Unauthorized();

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.Equal("You don't have permission to access this resource.", _controller.ViewBag.Message);
        }
    }

    // Minimal implementation to satisfy TempData requirements in tests
    internal class NullTempDataSerializer : SessionStateTempDataProvider
    {
        public NullTempDataSerializer() : base(new NullTempDataSerializerInner()) { }
    }

    internal class NullTempDataSerializerInner : ITempDataSerializer
    {
        public IDictionary<string, object> Deserialize(byte[] unprotectedData) => new Dictionary<string, object>();
        public byte[] Serialize(IDictionary<string, object> values) => Array.Empty<byte>();
    }
}

