using ContosoUniversity.Models;
using ContosoUniversity.Services;
using System;
using System.Collections.Generic;
using System.Linq;
using System.Threading.Tasks;
using Xunit;

namespace ContosoUniversity.Tests.Services
{
    public class NotificationServiceTests : IDisposable
    {
        private readonly NotificationService _service;

        public NotificationServiceTests()
        {
            _service = new NotificationService();
            // Drain the shared static queue before each test
            while (_service.ReceiveNotification() != null) { }
        }

        public void Dispose()
        {
            _service.Dispose();
        }

        [Fact]
        public void SendNotification_EnqueuesNotification()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE, "TestUser");

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("1", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
            Assert.Equal("TestUser", notification.CreatedBy);
            Assert.False(notification.IsRead);
        }

        [Fact]
        public void SendNotification_WithDisplayName_GeneratesCorrectMessage()
        {
            _service.SendNotification("Student", "1", "Carson Alexander", EntityOperation.CREATE, "Admin");

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Contains("Carson Alexander", notification.Message);
            Assert.Contains("Student", notification.Message);
            Assert.Contains("created", notification.Message);
        }

        [Fact]
        public void SendNotification_WithoutDisplayName_UsesIdInMessage()
        {
            _service.SendNotification("Student", "42", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Contains("ID: 42", notification.Message);
        }

        [Fact]
        public void SendNotification_DefaultUserIsSystem()
        {
            _service.SendNotification("Course", "100", EntityOperation.UPDATE);

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("System", notification.CreatedBy);
        }

        [Theory]
        [InlineData(EntityOperation.CREATE, "created")]
        [InlineData(EntityOperation.UPDATE, "updated")]
        [InlineData(EntityOperation.DELETE, "deleted")]
        public void SendNotification_GeneratesCorrectMessageForOperation(EntityOperation operation, string expectedVerb)
        {
            _service.SendNotification("Department", "1", "English", operation);

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Contains(expectedVerb, notification.Message);
        }

        [Fact]
        public void SendNotification_SetsOperationString()
        {
            _service.SendNotification("Course", "1", EntityOperation.UPDATE);
            var notification = _service.ReceiveNotification();
            Assert.Equal("UPDATE", notification.Operation);
        }

        [Fact]
        public void SendNotification_SetsCreatedAt()
        {
            var before = DateTime.Now.AddSeconds(-1);
            _service.SendNotification("Student", "1", EntityOperation.CREATE);
            var after = DateTime.Now.AddSeconds(1);

            var notification = _service.ReceiveNotification();
            Assert.InRange(notification.CreatedAt, before, after);
        }

        [Fact]
        public void ReceiveNotification_ReturnsNullWhenQueueEmpty()
        {
            var notification = _service.ReceiveNotification();
            Assert.Null(notification);
        }

        [Fact]
        public void ReceiveNotification_ReturnsFIFOOrder()
        {
            _service.SendNotification("Type1", "1", EntityOperation.CREATE);
            _service.SendNotification("Type2", "2", EntityOperation.UPDATE);
            _service.SendNotification("Type3", "3", EntityOperation.DELETE);

            var n1 = _service.ReceiveNotification();
            var n2 = _service.ReceiveNotification();
            var n3 = _service.ReceiveNotification();

            Assert.Equal("Type1", n1.EntityType);
            Assert.Equal("Type2", n2.EntityType);
            Assert.Equal("Type3", n3.EntityType);
        }

        [Fact]
        public void ReceiveNotification_RemovesFromQueue()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);

            var first = _service.ReceiveNotification();
            var second = _service.ReceiveNotification();

            Assert.NotNull(first);
            Assert.Null(second);
        }

        [Fact]
        public void MarkAsRead_DoesNotThrow()
        {
            // MarkAsRead is a no-op in the in-memory implementation
            var exception = Record.Exception(() => _service.MarkAsRead(1));
            Assert.Null(exception);
        }

        [Fact]
        public void SendNotification_OverloadWithoutDisplayName()
        {
            _service.SendNotification("Course", "5", EntityOperation.DELETE);

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("Course", notification.EntityType);
            Assert.Equal("5", notification.EntityId);
            Assert.Equal("DELETE", notification.Operation);
        }

        [Fact]
        public void Dispose_DoesNotThrow()
        {
            var service = new NotificationService();
            var exception = Record.Exception(() => service.Dispose());
            Assert.Null(exception);
        }

        [Fact]
        public void SendNotification_MultipleNotificationsCanBeQueued()
        {
            for (int i = 0; i < 20; i++)
            {
                _service.SendNotification("Entity", i.ToString(), EntityOperation.CREATE);
            }

            var received = new List<Notification>();
            Notification n;
            while ((n = _service.ReceiveNotification()) != null)
            {
                received.Add(n);
            }

            Assert.Equal(20, received.Count);
        }

        [Fact]
        public void SendNotification_WithEmptyDisplayName_UsesIdInMessage()
        {
            _service.SendNotification("Student", "42", "", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Contains("ID: 42", notification.Message);
        }

        [Fact]
        public void SendNotification_WithWhitespaceDisplayName_UsesIdInMessage()
        {
            _service.SendNotification("Student", "42", "   ", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Contains("ID: 42", notification.Message);
        }

        [Fact]
        public void SendNotification_CreateOperation_MessageFormat()
        {
            _service.SendNotification("Course", "100", "Chemistry", EntityOperation.CREATE);
            var n = _service.ReceiveNotification();
            Assert.Equal("New Course 'Chemistry' has been created", n.Message);
        }

        [Fact]
        public void SendNotification_UpdateOperation_MessageFormat()
        {
            _service.SendNotification("Course", "100", "Chemistry", EntityOperation.UPDATE);
            var n = _service.ReceiveNotification();
            Assert.Equal("Course 'Chemistry' has been updated", n.Message);
        }

        [Fact]
        public void SendNotification_DeleteOperation_MessageFormat()
        {
            _service.SendNotification("Course", "100", "Chemistry", EntityOperation.DELETE);
            var n = _service.ReceiveNotification();
            Assert.Equal("Course 'Chemistry' has been deleted", n.Message);
        }

        [Fact]
        public void SendNotification_WithoutDisplayName_CreateMessageFormat()
        {
            _service.SendNotification("Student", "42", EntityOperation.CREATE);
            var n = _service.ReceiveNotification();
            Assert.Equal("New Student (ID: 42) has been created", n.Message);
        }
    }
}

