        [Fact]
        public void DeleteConfirmed_RemovesInstructorAndRedirects()
        {
            // Use instructor 3 (Harui) who doesn't administer a department with InstructorID = 3
            // Actually instructor 3 has no department pointing to them as administrator, let me check
            // Department 1 -> InstructorID 1, Department 2 -> InstructorID 2
            // So instructor 3 (Harui) is safe to delete without department concerns

            var result = _controller.DeleteConfirmed(3);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
            Assert.Null(_context.Instructors.Find(3));
