using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class DepartmentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly DepartmentsController _controller;

        public DepartmentsControllerTests()
        {
            _context = TestDbContextHelper.CreateSeededContext();
            _controller = new DepartmentsController(_context);
            SetupController(_controller);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        private static void SetupController(Controller controller)
        {
            var httpContext = new DefaultHttpContext();
            controller.ControllerContext = new ControllerContext
            {
                HttpContext = httpContext
            };
            controller.TempData = new TempDataDictionary(
                httpContext, new TestTempDataProvider());
        }

        // --- Index tests ---

        [Fact]
        public void Index_ReturnsViewWithDepartments()
        {
            var result = _controller.Index();
            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<List<Department>>(viewResult.Model);
            Assert.Equal(2, model.Count);
        }

        // --- Details tests ---

        [Fact]
        public void Details_WithNullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_WithValidId_ReturnsViewWithDepartment()
        {
            var result = _controller.Details(1);
            var viewResult = Assert.IsType<ViewResult>(result);
            var department = Assert.IsType<Department>(viewResult.Model);
            Assert.Equal("English", department.Name);
        }

        [Fact]
        public void Details_WithInvalidId_ReturnsNotFound()
        {
            var result = _controller.Details(999);
            Assert.IsType<NotFoundResult>(result);
        }

        // --- Create GET tests ---

        [Fact]
        public void Create_Get_ReturnsView()
        {
            var result = _controller.Create();
            Assert.IsType<ViewResult>(result);
            Assert.NotNull(_controller.ViewBag.InstructorID);
        }

        // --- Create POST tests ---

        [Fact]
        public void Create_Post_ValidDepartment_RedirectsToIndex()
        {
            var department = new Department
            {
                Name = "Science",
                Budget = 200000,
                StartDate = new DateTime(2020, 9, 1),
                InstructorID = 1
            };

            var result = _controller.Create(department);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
        }

        [Fact]
        public void Create_Post_ValidDepartment_SavesToDB()
        {
            var department = new Department
            {
                Name = "Physics",
                Budget = 150000,
                StartDate = new DateTime(2020, 9, 1),
                InstructorID = 2
            };

            _controller.Create(department);

            var saved = _context.Departments.FirstOrDefault(d => d.Name == "Physics");
            Assert.NotNull(saved);
            Assert.Equal(150000, saved.Budget);
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("Name", "Required");
            var department = new Department
            {
                Budget = 200000,
                StartDate = new DateTime(2020, 9, 1)
            };

            var result = _controller.Create(department);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.NotNull(_controller.ViewBag.InstructorID);
        }

        // --- Edit GET tests ---

        [Fact]
        public void Edit_Get_WithNullId_ReturnsBadRequest()
        {
            var result = _controller.Edit(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_Get_WithValidId_ReturnsViewWithDepartment()
        {
            var result = _controller.Edit(1);
            var viewResult = Assert.IsType<ViewResult>(result);
            var department = Assert.IsType<Department>(viewResult.Model);
            Assert.Equal("English", department.Name);
            Assert.NotNull(_controller.ViewBag.InstructorID);
        }

        [Fact]
        public void Edit_Get_WithInvalidId_ReturnsNotFound()
        {
            var result = _controller.Edit(999);
            Assert.IsType<NotFoundResult>(result);
        }

        // --- Edit POST tests ---

        [Fact]
        public void Edit_Post_ValidDepartment_RedirectsToIndex()
        {
            var department = new Department
            {
                DepartmentID = 1,
                Name = "Updated English",
                Budget = 400000,
                StartDate = new DateTime(2007, 9, 1),
                InstructorID = 1
            };

            // Detach the existing tracked entity
            var existing = _context.Departments.Find(1);
            _context.Entry(existing).State = EntityState.Detached;

            var result = _controller.Edit(department);
            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
        }

        [Fact]
        public void Edit_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("Name", "Required");
            var department = new Department
            {
                DepartmentID = 1,
                Budget = 200000,
                StartDate = new DateTime(2020, 9, 1)
            };

            var result = _controller.Edit(department);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.NotNull(_controller.ViewBag.InstructorID);
        }

        // --- Delete GET tests ---

        [Fact]
        public void Delete_Get_WithNullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_Get_WithValidId_ReturnsViewWithDepartment()
        {
            var result = _controller.Delete(1);
            var viewResult = Assert.IsType<ViewResult>(result);
            var department = Assert.IsType<Department>(viewResult.Model);
            Assert.Equal("English", department.Name);
        }

        [Fact]
        public void Delete_Get_WithInvalidId_ReturnsNotFound()
        {
            var result = _controller.Delete(999);
            Assert.IsType<NotFoundResult>(result);
        }

        // --- Delete POST tests ---

        [Fact]
        public void DeleteConfirmed_RemovesDepartmentAndRedirects()
        {
            var result = _controller.DeleteConfirmed(1);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
            Assert.Null(_context.Departments.Find(1));
        }
    }
}

