using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class InstructorsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly InstructorsController _controller;

        public InstructorsControllerTests()
        {
            _context = TestDbContextHelper.CreateSeededContext();
            _controller = new InstructorsController(_context);
            SetupController(_controller);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        private static void SetupController(Controller controller)
        {
            var httpContext = new DefaultHttpContext();
            controller.ControllerContext = new ControllerContext
            {
                HttpContext = httpContext
            };
            controller.TempData = new TempDataDictionary(
                httpContext, new TestTempDataProvider());
        }

        // --- Index tests ---

        [Fact]
        public void Index_ReturnsViewWithInstructorIndexData()
        {
            var result = _controller.Index(null, null);
            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<InstructorIndexData>(viewResult.Model);
            Assert.NotNull(model.Instructors);
            Assert.Equal(3, model.Instructors.Count());
        }

        [Fact]
        public void Index_InstructorsOrderedByLastName()
        {
            var result = _controller.Index(null, null);
            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<InstructorIndexData>(viewResult.Model);
            var instructors = model.Instructors.ToList();

            Assert.Equal("Abercrombie", instructors[0].LastName);
            Assert.Equal("Fakhouri", instructors[1].LastName);
            Assert.Equal("Harui", instructors[2].LastName);
        }

        [Fact]
        public void Index_WithInstructorId_PopulatesCourses()
        {
            var result = _controller.Index(1, null); // Abercrombie
            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<InstructorIndexData>(viewResult.Model);

            Assert.NotNull(model.Courses);
            Assert.Single(model.Courses); // Abercrombie teaches 1 course in seed data (CourseID 1050)
        }

        [Fact]
        public void Index_WithInstructorId_SetsViewBag()
        {
            _controller.Index(1, null);
            Assert.Equal(1, (int)_controller.ViewBag.InstructorID);
        }

        // --- Details tests ---

        [Fact]
        public void Details_WithNullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_WithValidId_ReturnsViewWithInstructor()
        {
            var result = _controller.Details(1);
            var viewResult = Assert.IsType<ViewResult>(result);
            var instructor = Assert.IsType<Instructor>(viewResult.Model);
            Assert.Equal("Abercrombie", instructor.LastName);
        }

        [Fact]
        public void Details_WithInvalidId_ReturnsNotFound()
        {
            var result = _controller.Details(999);
            Assert.IsType<NotFoundResult>(result);
        }

        // --- Create GET tests ---

        [Fact]
        public void Create_Get_ReturnsViewWithInstructor()
        {
            var result = _controller.Create();
            var viewResult = Assert.IsType<ViewResult>(result);
            var instructor = Assert.IsType<Instructor>(viewResult.Model);
            Assert.NotNull(instructor.CourseAssignments);
            Assert.Empty(instructor.CourseAssignments);
            Assert.NotNull(_controller.ViewBag.Courses);
        }

        [Fact]
        public void Create_Get_PopulatesAssignedCourseData()
        {
            _controller.Create();
            var courses = _controller.ViewBag.Courses as List<AssignedCourseData>;
            Assert.NotNull(courses);
            Assert.Equal(2, courses.Count); // 2 courses in seed
            Assert.All(courses, c => Assert.False(c.Assigned));
        }

        // --- Create POST tests ---

        [Fact]
        public void Create_Post_ValidInstructor_RedirectsToIndex()
        {
            var instructor = new Instructor
            {
                FirstMidName = "New",
                LastName = "Instructor",
                HireDate = new DateTime(2020, 1, 15)
            };

            var result = _controller.Create(instructor, null);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
        }

        [Fact]
        public void Create_Post_ValidInstructor_SavesToDB()
        {
            var instructor = new Instructor
            {
                FirstMidName = "Saved",
                LastName = "NewProf",
                HireDate = new DateTime(2021, 3, 1)
            };

            _controller.Create(instructor, null);

            var saved = _context.Instructors.FirstOrDefault(i => i.LastName == "NewProf");
            Assert.NotNull(saved);
            Assert.Equal("Saved", saved.FirstMidName);
        }

        [Fact]
        public void Create_Post_WithSelectedCourses_AssignsCourses()
        {
            var instructor = new Instructor
            {
                FirstMidName = "CourseTest",
                LastName = "WithCourses",
                HireDate = new DateTime(2020, 1, 1)
            };

            var result = _controller.Create(instructor, new[] { "1050", "4022" });

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);

            var saved = _context.Instructors
                .Include(i => i.CourseAssignments)
                .FirstOrDefault(i => i.LastName == "WithCourses");
            Assert.NotNull(saved);
            Assert.Equal(2, saved.CourseAssignments.Count);
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var instructor = new Instructor
            {
                FirstMidName = "Test",
                HireDate = new DateTime(2020, 1, 1)
            };

            var result = _controller.Create(instructor, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.NotNull(_controller.ViewBag.Courses);
        }

        // --- Edit GET tests ---

        [Fact]
        public void Edit_Get_WithNullId_ReturnsBadRequest()
        {
            var result = _controller.Edit(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_Get_WithValidId_ReturnsViewWithInstructor()
        {
            var result = _controller.Edit(1);
            var viewResult = Assert.IsType<ViewResult>(result);
            var instructor = Assert.IsType<Instructor>(viewResult.Model);
            Assert.Equal("Abercrombie", instructor.LastName);
            Assert.NotNull(_controller.ViewBag.Courses);
        }

        // --- Delete GET tests ---

        [Fact]
        public void Delete_Get_WithNullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_Get_WithValidId_ReturnsViewWithInstructor()
        {
            var result = _controller.Delete(1);
            var viewResult = Assert.IsType<ViewResult>(result);
            var instructor = Assert.IsType<Instructor>(viewResult.Model);
            Assert.Equal("Abercrombie", instructor.LastName);
        }

        [Fact]
        public void Delete_Get_WithInvalidId_ReturnsNotFound()
        {
            var result = _controller.Delete(999);
            Assert.IsType<NotFoundResult>(result);
        }

        // --- DeleteConfirmed tests ---

        [Fact]
        public void DeleteConfirmed_RemovesInstructorAndRedirects()
        {
            // Use instructor 3 (Harui) who doesn't administer a department with InstructorID = 3
            // Actually instructor 3 has no department pointing to them as administrator, let me check
            // Department 1 -> InstructorID 1, Department 2 -> InstructorID 2
            // So instructor 3 (Harui) is safe to delete without department concerns

            var result = _controller.DeleteConfirmed(3);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
            Assert.Null(_context.Instructors.Find(3));
        }

        [Fact]
        public void DeleteConfirmed_UnsetsDepartmentAdmin()
        {
            // Instructor 1 (Abercrombie) is admin of Department 1 (English)
            _controller.DeleteConfirmed(1);

            var department = _context.Departments.Find(1);
            Assert.Null(department.InstructorID);
        }
    }
}

