using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.EntityFrameworkCore;
using System;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class SchoolContextTests : IDisposable
    {
        private readonly SchoolContext _context;

        public SchoolContextTests()
        {
            _context = TestDbContextHelper.CreateSeededContext();
        }

        public void Dispose()
        {
            _context.Dispose();
        }

        [Fact]
        public void Context_CanQueryStudents()
        {
            var students = _context.Students.ToList();
            Assert.Equal(3, students.Count);
        }

        [Fact]
        public void Context_CanQueryInstructors()
        {
            var instructors = _context.Instructors.ToList();
            Assert.Equal(3, instructors.Count);
        }

        [Fact]
        public void Context_CanQueryCourses()
        {
            var courses = _context.Courses.ToList();
            Assert.Equal(2, courses.Count);
        }

        [Fact]
        public void Context_CanQueryDepartments()
        {
            var departments = _context.Departments.ToList();
            Assert.Equal(2, departments.Count);
        }

        [Fact]
        public void Context_CanQueryEnrollments()
        {
            var enrollments = _context.Enrollments.ToList();
            Assert.Equal(3, enrollments.Count);
        }

        [Fact]
        public void Context_CanQueryOfficeAssignments()
        {
            var officeAssignments = _context.OfficeAssignments.ToList();
            Assert.Single(officeAssignments);
        }

        [Fact]
        public void Context_CanQueryCourseAssignments()
        {
            var courseAssignments = _context.CourseAssignments.ToList();
            Assert.Equal(2, courseAssignments.Count);
        }

        [Fact]
        public void Context_StudentIncludesEnrollments()
        {
            var student = _context.Students
                .Include(s => s.Enrollments)
                .First(s => s.ID == 10);

            Assert.NotNull(student.Enrollments);
            Assert.Equal(2, student.Enrollments.Count);
        }

        [Fact]
        public void Context_CourseIncludesDepartment()
        {
            var course = _context.Courses
                .Include(c => c.Department)
                .First(c => c.CourseID == 1050);

            Assert.NotNull(course.Department);
            Assert.Equal("English", course.Department.Name);
        }

        [Fact]
        public void Context_InstructorIncludesOfficeAssignment()
        {
            var instructor = _context.Instructors
                .Include(i => i.OfficeAssignment)
                .First(i => i.ID == 2);

            Assert.NotNull(instructor.OfficeAssignment);
            Assert.Equal("Smith 17", instructor.OfficeAssignment.Location);
        }

        [Fact]
        public void Context_CanAddAndRetrieveStudent()
        {
            var student = new Student
            {
                FirstMidName = "New",
                LastName = "Student",
                EnrollmentDate = new DateTime(2023, 1, 1)
            };
            _context.Students.Add(student);
            _context.SaveChanges();

            var saved = _context.Students.First(s => s.LastName == "Student");
            Assert.Equal("New", saved.FirstMidName);
        }

        [Fact]
        public void Context_CanDeleteStudent()
        {
            var student = _context.Students.Find(12);
            Assert.NotNull(student);

            _context.Students.Remove(student);
            _context.SaveChanges();

            Assert.Null(_context.Students.Find(12));
        }

        [Fact]
        public void Context_CanUpdateStudent()
        {
            var student = _context.Students.Find(10);
            student.LastName = "UpdatedName";
            _context.SaveChanges();

            var updated = _context.Students.Find(10);
            Assert.Equal("UpdatedName", updated.LastName);
        }
    }

    public class DbInitializerTests
    {
        [Fact]
        public void Initialize_SeedsDataInEmptyDatabase()
        {
            var context = TestDbContextHelper.CreateContext();

            DbInitializer.Initialize(context);

            Assert.True(context.Students.Any());
            Assert.True(context.Instructors.Any());
            Assert.True(context.Departments.Any());
            Assert.True(context.Courses.Any());
            Assert.True(context.Enrollments.Any());
            Assert.True(context.OfficeAssignments.Any());
            Assert.True(context.CourseAssignments.Any());

            context.Dispose();
        }

        [Fact]
        public void Initialize_DoesNotReseedWhenDataExists()
        {
            var context = TestDbContextHelper.CreateContext();
            DbInitializer.Initialize(context);

            var originalCount = context.Students.Count();

            // Initialize again
            DbInitializer.Initialize(context);

            Assert.Equal(originalCount, context.Students.Count());

            context.Dispose();
        }
    }
}

