using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using System;
using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class HomeControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly HomeController _controller;

        public HomeControllerTests()
        {
            _context = TestDbContextHelper.CreateSeededContext();
            _controller = new HomeController(_context);
            SetupController(_controller);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        private static void SetupController(Controller controller)
        {
            controller.ControllerContext = new ControllerContext
            {
                HttpContext = new DefaultHttpContext()
            };
            controller.TempData = new TempDataDictionary(
                controller.ControllerContext.HttpContext,
                new SessionStateTempDataProvider(new NullTempDataSerializer()));
        }

        [Fact]
        public void Index_ReturnsViewResult()
        {
            var result = _controller.Index();
            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void About_ReturnsViewResultWithEnrollmentDateGroups()
        {
            var result = _controller.About();

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<List<EnrollmentDateGroup>>(viewResult.Model);
            Assert.NotEmpty(model);
        }

        [Fact]
        public void About_GroupsStudentsByEnrollmentDate()
        {
            var result = _controller.About();
            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<List<EnrollmentDateGroup>>(viewResult.Model);

            // We have 3 students with dates: 2010-09-01, 2012-09-01, 2013-09-01
            Assert.Equal(3, model.Count);
            Assert.All(model, g => Assert.True(g.StudentCount > 0));
        }

        [Fact]
        public void Contact_ReturnsViewResult()
        {
            var result = _controller.Contact();

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.Equal("Your contact page.", _controller.ViewBag.Message);
        }

        [Fact]
        public void Error_ReturnsViewResult()
        {
            var result = _controller.Error();
            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Unauthorized_ReturnsViewResult()
        {
            var result = _controller.Unauthorized();

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.Equal("You don't have permission to access this resource.", _controller.ViewBag.Message);
        }
    }

    // Minimal implementation to satisfy TempData requirements in tests
    internal class NullTempDataSerializer : SessionStateTempDataProvider
    {
        public NullTempDataSerializer() : base(new NullTempDataSerializerInner()) { }
    }

    internal class NullTempDataSerializerInner : ITempDataSerializer
    {
        public IDictionary<string, object> Deserialize(byte[] unprotectedData) => new Dictionary<string, object>();
        public byte[] Serialize(IDictionary<string, object> values) => Array.Empty<byte>();
    }
}

